-- ---- Stub: lurek.mods.newMod ---------------------------------------------
--@api-stub: lurek.mods.newMod
-- Create a Mod descriptor in code to expose a documented extension point
-- without requiring a separate mod.toml on disk.
local hero_mod = lurek.mods.newMod({
    id          = "hero_overhaul",
    name        = "Hero Overhaul",
    version     = "1.2.0",
    author      = "Modder McModface",
    description = "Replaces hero sprites and tweaks movement speed.",
    priority    = 10,
})
print("mod created:", hero_mod:getId())

-- ---- Stub: lurek.mods.newModManager --------------------------------------
--@api-stub: lurek.mods.newModManager
-- Centralise mod discovery, load-order, and dependency checking behind one
-- object -- instantiate once at startup and pass it to your mod loader.
local mgr = lurek.mods.newModManager()
print("ModManager created, mod count:", mgr:getModCount())

-- ---- Stub: lurek.mods.checkApiVersion ------------------------------------
--@api-stub: lurek.mods.checkApiVersion
-- Validate a mod's required engine version before loading it -- fail fast
-- with a friendly message instead of crashing inside a hook.
local compat = lurek.mods.checkApiVersion(hero_mod, "0.5.0")
if compat then
    print("version compatible:", compat.compatible)
else
    print("mod requires a newer engine version")
end

